import{b as a,I as n,g as t,j as s}from"./chunks/framework.DUo3J_Qe.js";const m=JSON.parse('{"title":"Réseaux de neurones convolutifs (CNN)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/deep-learning/cnn.md","filePath":"fr/learning/deep-learning/cnn.md"}'),r={name:"fr/learning/deep-learning/cnn.md"};function o(i,e,l,u,c,d){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="reseaux-de-neurones-convolutifs-cnn" tabindex="-1">Réseaux de neurones convolutifs (CNN) <a class="header-anchor" href="#reseaux-de-neurones-convolutifs-cnn" aria-label="Permalink to &quot;Réseaux de neurones convolutifs (CNN)&quot;">​</a></h1><h2 id="pourquoi-pas-un-reseau-classique" tabindex="-1">Pourquoi pas un réseau classique ? <a class="header-anchor" href="#pourquoi-pas-un-reseau-classique" aria-label="Permalink to &quot;Pourquoi pas un réseau classique ?&quot;">​</a></h2><p>Un réseau de neurones classique (fully connected) traite chaque pixel indépendamment. Une image 256×256 en RGB → 196 608 valeurs en entrée. Le réseau ne &quot;voit&quot; aucune relation spatiale : le pixel en haut à gauche et celui juste à côté sont traités comme s&#39;ils n&#39;avaient aucun lien.</p><p>Un <strong>CNN</strong> résout ce problème avec des <strong>filtres convolutifs</strong> — de petites fenêtres qui glissent sur l&#39;image et détectent des motifs locaux (bords, textures, formes).</p><h2 id="la-convolution-en-images" tabindex="-1">La convolution en images <a class="header-anchor" href="#la-convolution-en-images" aria-label="Permalink to &quot;La convolution en images&quot;">​</a></h2><p>Un filtre est une petite matrice (ex. 3×3) qu&#39;on fait glisser sur l&#39;image. À chaque position, on multiplie les valeurs du filtre par les pixels sous-jacents et on additionne. Le résultat est un nouveau pixel dans la <strong>carte d&#39;activation</strong> (feature map).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image                Filtre 3×3           Feature map</span></span>
<span class="line"><span>┌─────────────┐      ┌───┬───┬───┐        ┌──────────┐</span></span>
<span class="line"><span>│ 10  20  30  │  ×   │ 1 │ 0 │-1 │   =    │   ...    │</span></span>
<span class="line"><span>│ 40  50  60  │      │ 1 │ 0 │-1 │        │   ...    │</span></span>
<span class="line"><span>│ 70  80  90  │      │ 1 │ 0 │-1 │        └──────────┘</span></span>
<span class="line"><span>└─────────────┘      └───┴───┴───┘</span></span></code></pre></div><p>Ce filtre détecte les bords verticaux. D&#39;autres filtres détectent des bords horizontaux, des coins, des textures, etc.</p><h2 id="ce-que-le-cnn-apprend" tabindex="-1">Ce que le CNN apprend <a class="header-anchor" href="#ce-que-le-cnn-apprend" aria-label="Permalink to &quot;Ce que le CNN apprend&quot;">​</a></h2><p>Un CNN est organisé en <strong>couches successives</strong> :</p><table tabindex="0"><thead><tr><th>Couche</th><th>Ce qu&#39;elle détecte</th></tr></thead><tbody><tr><td>Couche 1</td><td>Bords, contrastes locaux</td></tr><tr><td>Couche 2</td><td>Textures, motifs simples</td></tr><tr><td>Couche 3</td><td>Formes (cercles, arcs)</td></tr><tr><td>Couches profondes</td><td>Objets complexes (couronne d&#39;arbre, toit)</td></tr></tbody></table><p>Les filtres ne sont <strong>pas programmés à la main</strong> — le réseau les apprend automatiquement à partir des exemples d&#39;entraînement.</p><h2 id="operations-cles" tabindex="-1">Opérations clés <a class="header-anchor" href="#operations-cles" aria-label="Permalink to &quot;Opérations clés&quot;">​</a></h2><p><strong>Pooling</strong> — réduit la taille de la feature map (ex. garder le max dans une fenêtre 2×2). Le réseau devient insensible aux petits décalages de position.</p><p><strong>ReLU</strong> — fonction d&#39;activation <code>max(0, x)</code>. Elle introduit de la non-linéarité : sans elle, empiler des couches ne servirait à rien (une somme de fonctions linéaires reste linéaire).</p><p><strong>Padding</strong> — ajoute des pixels nuls autour de l&#39;image pour que la feature map garde la même taille après convolution.</p><h2 id="analogie-web" tabindex="-1">Analogie web <a class="header-anchor" href="#analogie-web" aria-label="Permalink to &quot;Analogie web&quot;">​</a></h2><p>Pense à un CNN comme à une pipeline de transformations CSS/SVG : chaque couche applique un filtre (blur, sharpen, edge-detect) sur l&#39;image précédente. La différence : les filtres sont appris, pas codés.</p><h2 id="cnn-→-segmentation" tabindex="-1">CNN → segmentation <a class="header-anchor" href="#cnn-→-segmentation" aria-label="Permalink to &quot;CNN → segmentation&quot;">​</a></h2><p>Un CNN classique se termine par une couche fully connected qui produit <strong>un seul vecteur de probabilités</strong> (classification). Pour la segmentation, on a besoin d&#39;une sortie de la même taille que l&#39;entrée (un label par pixel). C&#39;est le rôle de l&#39;architecture <strong>U-Net</strong>.</p>`,20)])])}const h=a(r,[["render",o]]);export{m as __pageData,h as default};
